import json

# Get company data from stockinfo
companies = locals()['var_functions.query_db:46']

# Build company info lookup (excluding ETFs)
company_info = {}
for company in companies:
    symbol = company['Symbol']
    desc = company['Company Description']

    # Skip ETFs and test issues
    if 'etf' in desc.lower() or 'etn' in desc.lower() or 'test' in desc.lower():
        continue

    # Extract company name
    name = desc.split('.')[0].split(',')[0].split(' specializes in')[0].split(' is ')[0].split(' harnesses')[0].strip()
    if symbol == 'FTR':
        name = 'Frontier Communications Corporation'

    company_info[symbol] = {
        'name': name,
        'financial_status': company['Financial Status']
    }

print('__RESULT__:')
print(json.dumps({
    'symbols': list(company_info.keys()),
    'count': len(company_info),
    'info': company_info
}))

